"""
Parameterized generator for GH341_hrm_3714.

Source PR:    https://github.com/arii/hrm/pull/3714
Source Issue: https://github.com/arii/hrm/issues/3680

Seed varies: renames 'access' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH341_hrm_3714'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH341_hrm_3714'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('access', 'access' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH341_hrm_3714',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'arii/hrm',
                "pr_number": 3714,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/arii/hrm/pull/3714",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'lib/auth.ts': "// File: lib/auth.ts (NextAuth Configuration - Shared)\nimport { Account, AuthOptions, Session } from 'next-auth'\nimport { JWT } from 'next-auth/jwt'\nimport SpotifyProvider from 'next-auth/providers/spotify'\nimport logger from '@/utils/logger'\nimport { getAPIURL } from '../utils/urls'\nimport { env } from './env'\nimport { refreshSpotifyToken } from './spotify'\n\n// Extend the Session type to include accessToken and error\ndeclare module 'next-auth' {\n  interface Session {\n    accessToken?: string\n    error?: string\n  }\n}\n\n// Extend the JWT type to include custom properties\ndeclare module 'next-auth/jwt' {\n  interface JWT {\n    accessToken?: string\n    accessTokenExpires?: number\n    refreshToken?: string\n    error?: string\n    providerAccountId?: string\n    scope?: string\n  }\n}\n\n// Helper to sync token with backend\nasync function syncTokenWithBackend(token: JWT) {\n  try {\n    const tokenPayload = {\n      provider: 'spotify',\n      sub: token.providerAccountId, // providerAccountId is mapped to sub in JWT usually\n      access_token: token.accessToken,\n      refresh_token: token.refreshToken,\n      expires_in: Math.floor(\n        ((token.accessTokenExpires as number) - Date.now()) / 1000\n      ),\n      scope: token.scope || '', // Ensure scope is preserved in JWT if needed\n      obtainedAt: Date.now(),\n    }\n    // Only sync if we have valid data\n    if (!tokenPayload.access_token || !tokenPayload.refresh_token) return\n\n    const response = await fetch(getAPIURL('internal/token-delivery'), {\n      method: 'POST',\n      headers: {\n        'Content-Type': 'application/json',\n        'x-internal-token-secret': env.NEXTAUTH_SECRET,\n      },\n      body: JSON.stringify(tokenPayload),\n    })\n\n    if (response.ok) {\n      logger.debug('Token successfully synced with the backend.')\n    } else {\n      logger.warn(\n        {\n          status: response.status,\n          body: await response.text(),\n        },\n        'Failed to sync token with the backend.'\n      )\n    }\n  } catch (e) {\n    logger.error({ error: e }, 'Failed to sync refreshed token with backend')\n  }\n}\n\n/**\n * Safely extracts the hostname from the `NEXTAUTH_URL` environment variable to be used\n * as the domain for NextAuth cookies. This prevents cookie domain errors by returning\n * `undefined` for invalid URLs or for local development environments (`localhost`, `127.0.0.1`),\n * allowing the browser to default to the current domain.\n *\n * @returns {string | undefined} The hostname for the cookie domain, or `undefined` if it\n *                               should not be set.\n */\nfunction getCookieDomain(): string | undefined {\n  if (!env.NEXTAUTH_URL) {\n    return undefined\n  }\n  try {\n    const url = new URL(env.NEXTAUTH_URL)\n    // For localhost and 127.0.0.1, don't set a domain (browsers will use current domain)\n    if (url.hostname === 'localhost' || url.hostname === '127.0.0.1') {\n      return undefined\n    }\n    return url.hostname\n  } catch (e) {\n    logger.error(\n      { url: env.NEXTAUTH_URL, error: e },\n      'Failed to parse NEXTAUTH_URL for cookie domain'\n    )\n    return undefined\n  }\n}\n\n/**\n * @file NextAuth configuration for Spotify authentication.\n * @module lib/auth\n */\n\n/**\n * Refreshes an expired Spotify access token using a refresh token.\n *\n * This function is invoked by the NextAuth JWT callback when an access token\n * is expired. It posts to Spotify's token endpoint to get a new access token\n * and updates the token object with the new credentials.\n *\n * @param {JWT} token The JWT from NextAuth containing the expired accessToken\n *                    and the valid refreshToken.\n * @returns {Promise<JWT>} The updated JWT with a new accessToken and expiry,\n *                         or the original token with an error flag if refresh fails.\n */\nasync function refreshAccessToken(token: JWT) {\n  try {\n    const refreshedTokens = await refreshSpotifyToken(\n      token.refreshToken as string\n    )\n\n    // Update the token object with new values from Spotify\n    return {\n      ...token,\n      accessToken: refreshedTokens.access_token,\n      accessTokenExpires: Date.now() + refreshedTokens.expires_in * 1000,\n      // Note: Spotify might or might not send a new refresh token.\n      // If it does, use it. If not, keep the old one.\n      refreshToken: refreshedTokens.refresh_token ?? token.refreshToken,\n      scope: refreshedTokens.scope ?? token.scope, // Persist the scope\n    }\n  } catch (error) {\n    logger.error({ error }, 'Failed to refresh access token')\n    // If refresh fails, return the original token and an error property\n    return {\n      ...token,\n      error: 'RefreshAccessTokenError',\n    }\n  }\n}\n\n// Define scopes required: user-read-playback-state to poll the current track,\n// user-modify-playback-state to control playback (play/pause/skip),\n// streaming for Web Playback SDK (play music in browser).\nconst SPOTIFY_SCOPES = [\n  'user-read-private',\n  'user-top-read',\n  'user-read-email',\n  'user-read-playback-state',\n  'user-modify-playback-state',\n  'user-read-currently-playing',\n  'streaming', // Required for Web Playback SDK\n].join(',')\n\n// --- CRITICAL SECURITY CHECK ---\n// Ensure NEXTAUTH_SECRET is explicitly checked before configuration.\n// This prevents runtime errors and insecure defaults.\nconst NEXTAUTH_SECRET = env.NEXTAUTH_SECRET\n\nif (!NEXTAUTH_SECRET) {\n  throw new Error(\n    'NEXTAUTH_SECRET environment variable is not defined. This is a critical security requirement.'\n  )\n}\n\n/**\n * Configuration options for NextAuth.js.\n *\n * This object defines the authentication providers, callbacks, and other settings\n * for managing user sessions and authentication flows. It is configured to use the\n * Spotify provider with specific scopes required for the application's features.\n *\n * @type {AuthOptions}\n */\n\nconst providers = []\n\nif (env.SPOTIFY_CLIENT_ID && env.SPOTIFY_CLIENT_SECRET) {\n  providers.push(\n    SpotifyProvider({\n      clientId: env.SPOTIFY_CLIENT_ID,\n      clientSecret: env.SPOTIFY_CLIENT_SECRET,\n      authorization: {\n        params: {\n          scope: SPOTIFY_SCOPES,\n        },\n      },\n    })\n  )\n}\n\nexport const authOptions: AuthOptions = {\n  providers,\n  // In NextAuth v4, URL is automatically detected from NEXTAUTH_URL env var\n  cookies: {\n    sessionToken: {\n      name: `next-auth.session-token`,\n      options: {\n        httpOnly: true,\n        sameSite: 'lax',\n        path: '/',\n        secure: env.NODE_ENV === 'production',\n        domain: getCookieDomain(),\n      },\n    },\n    callbackUrl: {\n      name: `next-auth.callback-url`,\n      options: {\n        httpOnly: true,\n        sameSite: 'lax',\n        path: '/',\n        secure: env.NODE_ENV === 'production',\n        domain: getCookieDomain(),\n      },\n    },\n    csrfToken: {\n      name: `next-auth.csrf-token`,\n      options: {\n        httpOnly: true,\n        sameSite: 'lax',\n        path: '/',\n        secure: env.NODE_ENV === 'production',\n        domain: getCookieDomain(),\n      },\n    },\n    pkceCodeVerifier: {\n      name: `next-auth.pkce.code_verifier`,\n      options: {\n        httpOnly: true,\n        sameSite: 'lax',\n        path: '/',\n        secure: env.NODE_ENV === 'production',\n        maxAge: 900, // 15 minutes\n        domain: getCookieDomain(),\n      },\n    },\n    state: {\n      name: `next-auth.state`,\n      options: {\n        httpOnly: true,\n        sameSite: 'lax',\n        path: '/',\n        secure: env.NODE_ENV === 'production',\n        maxAge: 900, // 15 minutes\n        domain: getCookieDomain(),\n      },\n    },\n  },\n  useSecureCookies: env.NODE_ENV === 'production',\n  debug: env.NODE_ENV === 'development',\n  callbacks: {\n    /**\n     * Callback executed on a successful sign-in.\n     *\n     * @returns {boolean} Always returns true to allow sign-in.\n     */\n    async signIn() {\n      // Always allow Spotify sign-in\n      return true\n    },\n    /**\n     * Callback for creating and managing the JSON Web Token (JWT).\n     *\n     * This function is called whenever a JWT is created (i.e., at sign-in) or\n     * updated (i.e., whenever a session is accessed in the client). It is\n     * responsible for persisting the Spotify access token and refresh token\n     * in the JWT.\n     *\n     * @param {object} params - The parameters for the JWT callback.\n     * @param {JWT} params.token - The JWT token.\n     * @param {Account | null} params.account - The account object from the provider.\n     * @returns {Promise<JWT>} The updated JWT.\n     */\n    async jwt({ token, account }: { token: JWT; account: Account | null }) {\n      // 1. Initial sign-in\n      if (account) {\n        // ... [Existing initial sign-in logic] ...\n        // Ensure you preserve the 'sub' or providerAccountId for future syncs\n        const initialToken = {\n          ...token,\n          accessToken: account.access_token,\n          accessTokenExpires:\n            Date.now() + (Number(account.expires_in) || 3600) * 1000,\n          refreshToken: account.refresh_token,\n          providerAccountId: account.providerAccountId, // Store ID for reference\n          scope: account.scope,\n        }\n\n        // Sync on initial login\n        syncTokenWithBackend(initialToken).catch((err) =>\n          logger.error({ err }, 'Background token sync failed on initial login')\n        )\n\n        return initialToken\n      }\n\n      // 2. Token is still valid\n      if (Date.now() < (token.accessTokenExpires as number) - 60000) {\n        return token\n      }\n\n      // 3. Token is expired - Refresh it\n      logger.info('[AUTH] Access token expired, refreshing...')\n\n      // Perform the refresh\n      const refreshedToken = await refreshAccessToken(token)\n\n      // CRITICAL FIX: Sync the NEW refreshed token to the backend\n      if (!refreshedToken.error) {\n        // Run in background to not block the session response\n        syncTokenWithBackend(refreshedToken).catch((err) =>\n          logger.error({ err }, 'Background token sync failed')\n        )\n      }\n\n      return refreshedToken\n    },\n    /**\n     * Callback for creating and managing the user session.\n     *\n     * This function is called whenever a session is checked. It passes the\n     * access token from the JWT to the client-side session object.\n     *\n     * @param {object} params - The parameters for the session callback.\n     * @param {Session} params.session - The session object.\n     * @param {JWT} params.token - The JWT token.\n     * @returns {Promise<Session>} The updated session object.\n     */\n    async session({ session, token }: { session: Session; token: JWT }) {\n      // Pass the updated token and error info to the session object\n      logger.debug({ tokenKeys: Object.keys(token) }, 'Creating session')\n      session.accessToken = token.accessToken as string\n      session.error = token.error as string // Pass any refresh errors\n      logger.debug({ hasAccessToken: !!session.accessToken }, 'Session created')\n      return session\n    },\n  },\n  // Ensure the token can be accessed securely\n  secret: NEXTAUTH_SECRET,\n}\n",
            'tests/unit/lib/auth.test.ts': '/**\n * @jest-environment node\n */\nimport { authOptions } from \'@/lib/auth\'\nimport * as spotify from \'@/lib/spotify\'\nimport { Account } from \'next-auth\'\nimport { JWT } from \'next-auth/jwt\'\n\n// Mock the spotify module\njest.mock(\'@/lib/spotify\', () => ({\n  refreshSpotifyToken: jest.fn(),\n}))\n\n// Mock the logger\njest.mock(\'@/utils/logger\', () => ({\n  __esModule: true,\n  default: {\n    info: jest.fn(),\n    error: jest.fn(),\n    debug: jest.fn(),\n  },\n}))\n\nglobal.fetch = jest.fn()\n\ndescribe(\'authOptions.callbacks.jwt\', () => {\n  const jwtCallback = authOptions.callbacks?.jwt\n\n  if (!jwtCallback) {\n    throw new Error(\'JWT callback is not defined in authOptions\')\n  }\n\n  const baseToken: JWT = {\n    name: \'Test User\',\n    email: \'test@example.com\',\n    sub: \'12345\',\n  }\n\n  afterEach(() => {\n    jest.clearAllMocks()\n  })\n\n  it(\'should handle initial sign-in correctly, including scope\', async () => {\n    const account = {\n      provider: \'spotify\',\n      providerAccountId: \'spotify-user-id\',\n      access_token: \'initial-access-token\',\n      refresh_token: \'initial-refresh-token\',\n      expires_in: 3600,\n      scope: \'user-read-private user-read-email\',\n    }\n    const token = { ...baseToken }\n\n    // Mock the fetch call for token delivery\n    ;(fetch as jest.Mock).mockResolvedValueOnce({\n      ok: true,\n    })\n\n    const result = await jwtCallback({ token, account: account as Account })\n\n    expect(result.accessToken).toBe(account.access_token)\n    expect(result.refreshToken).toBe(account.refresh_token)\n    expect(result.providerAccountId).toBe(account.providerAccountId)\n    expect(result.scope).toBe(account.scope)\n    expect(fetch).toHaveBeenCalledWith(\n      expect.stringContaining(\'internal/token-delivery\'),\n      expect.objectContaining({\n        method: \'POST\',\n        body: expect.stringContaining(account.providerAccountId),\n      })\n    )\n  })\n\n  it(\'should return the token if it is still valid\', async () => {\n    const token: JWT = {\n      ...baseToken,\n      accessToken: \'valid-access-token\',\n      accessTokenExpires: Date.now() + 120000, // Expires in 120 seconds\n    }\n\n    const result = await jwtCallback({ token, account: null })\n\n    expect(result).toBe(token)\n    expect(spotify.refreshSpotifyToken).not.toHaveBeenCalled()\n  })\n\n  it(\'should refresh the token if it is expired and persist scope\', async () => {\n    const token: JWT = {\n      ...baseToken,\n      accessToken: \'expired-access-token\',\n      refreshToken: \'current-refresh-token\',\n      accessTokenExpires: Date.now() - 1000, // Expired 1 second ago\n      providerAccountId: \'spotify-user-id\',\n      scope: \'user-read-private user-read-email\',\n    }\n    const refreshedTokens = {\n      access_token: \'refreshed-access-token\',\n      expires_in: 3600,\n      refresh_token: \'new-refresh-token\',\n      // No new scope returned from refresh\n    }\n\n    ;(spotify.refreshSpotifyToken as jest.Mock).mockResolvedValue(\n      refreshedTokens\n    )\n    ;(fetch as jest.Mock).mockResolvedValueOnce({\n      ok: true,\n    })\n\n    const result = await jwtCallback({ token, account: null })\n\n    expect(spotify.refreshSpotifyToken).toHaveBeenCalledWith(token.refreshToken)\n    expect(result.accessToken).toBe(refreshedTokens.access_token)\n    expect(result.refreshToken).toBe(refreshedTokens.refresh_token)\n    expect(result.scope).toBe(token.scope) // Ensure scope is carried over\n    expect(fetch).toHaveBeenCalledWith(\n      expect.stringContaining(\'internal/token-delivery\'),\n      expect.objectContaining({\n        method: \'POST\',\n        body: expect.stringContaining(refreshedTokens.access_token),\n      })\n    )\n  })\n\n  it(\'should return an error if token refresh fails\', async () => {\n    const token: JWT = {\n      ...baseToken,\n      accessToken: \'expired-access-token\',\n      refreshToken: \'current-refresh-token\',\n      accessTokenExpires: Date.now() - 1000,\n    }\n\n    ;(spotify.refreshSpotifyToken as jest.Mock).mockRejectedValue(\n      new Error(\'Refresh failed\')\n    )\n\n    const result = await jwtCallback({ token, account: null })\n\n    expect(result.error).toBe(\'RefreshAccessTokenError\')\n    expect(fetch).not.toHaveBeenCalled()\n  })\n\n  it(\'should update scope if a new one is returned on refresh\', async () => {\n    const token: JWT = {\n      ...baseToken,\n      accessToken: \'expired-access-token\',\n      refreshToken: \'current-refresh-token\',\n      accessTokenExpires: Date.now() - 1000,\n      scope: \'old-scope\',\n    }\n    const refreshedTokens = {\n      access_token: \'refreshed-access-token\',\n      expires_in: 3600,\n      scope: \'new-scope\',\n    }\n\n    ;(spotify.refreshSpotifyToken as jest.Mock).mockResolvedValue(\n      refreshedTokens\n    )\n    ;(fetch as jest.Mock).mockResolvedValueOnce({ ok: true })\n\n    const result = await jwtCallback({ token, account: null })\n\n    expect(result.scope).toBe(refreshedTokens.scope)\n    expect(fetch).toHaveBeenCalledWith(\n      expect.stringContaining(\'internal/token-delivery\'),\n      expect.objectContaining({\n        body: expect.stringContaining(\'"scope":"new-scope"\'),\n      })\n    )\n  })\n})\n',
        }
